<?php
function parseUserConfig($xmlContent) {
    // Disable external entity loader to prevent XXE attacks
    libxml_disable_entity_loader(true);
    // Enable internal error handling
    libxml_use_internal_errors(true);

    // Load the XML string
    $xml = simplexml_load_string($xmlContent, 'SimpleXMLElement', LIBXML_NOCDATA);
    if ($xml === false) {
        $errors = libxml_get_errors();
        libxml_clear_errors();
        throw new Exception("Failed to load XML configuration: " . implode(", ", array_map(function($error) {
            return trim($error->message);
        }, $errors)));
    }

    // Extract configuration settings into an associative array
    $settings = [];
    foreach ($xml->children() as $element) {
        // If the setting is defined with a 'name' attribute: <setting name="key">value</setting>
        $attributes = $element->attributes();
        if (isset($attributes['name'])) {
            $key = (string)$attributes['name'];
        } else {
            $key = $element->getName();
        }
        $settings[$key] = (string)$element;
    }

    return $settings;
}

